mapper.select:
/*canPpTransferMapper.getRcgRmoteReqLogDelList*/

SELECT 
	A.REQ_SEQ, TO_CHAR(A.IN_REQ_DATE, 'YYYYMMDDHH24MISS') IN_REQ_DT
FROM PPS_RCG_REMOTE_REQ_LOG@DL_CAN A
WHERE TO_DATE(TO_CHAR(IN_REQ_DATE, 'YYYYMMDD'), 'YYYYMMDD') < TRUNC(SYSDATE) - #{stdrCnt}

mapper.insert:
	/*canPpTransferMapper.insertCanPpsRcgArs*/
	INSERT INTO PPS_RCG_ARS@DL_CAN (
		ARS_SEQ, REQ_TYPE, CONTRACT_NUM, RECHARGE, BASIC_REMAINS, BASIC_EXPIRE, DATA_VA_REMAINS, DATA_EXPIRE, 
		RECHARGE_INFO, RET_CODE, RET_MSG, RCG_SEQ, CONN_NUMBER, CID, REQ_DATE, PIN_NUMBER, TRANSFER_DTTM
	)
	SELECT ARS_SEQ, REQ_TYPE, CONTRACT_NUM, RECHARGE, BASIC_REMAINS, BASIC_EXPIRE, DATA_VA_REMAINS, DATA_EXPIRE, 
		RECHARGE_INFO, RET_CODE, RET_MSG, RCG_SEQ, CONN_NUMBER, CID, REQ_DATE, PIN_NUMBER, SYSDATE
	FROM PPS_RCG_ARS A
	WHERE CONTRACT_NUM = #{contractNum}
  		AND NOT EXISTS (SELECT 1 FROM PPS_RCG_ARS@DL_CAN WHERE CONTRACT_NUM = A.CONTRACT_NUM)

mapper.update:
/*canPpTransferMapper.updatePpsRcgArs*/
UPDATE PPS_RCG_ARS SET 
	CID = LPAD('0', LENGTH(CID), '0')
	, RECHARGE_INFO = LPAD('0', LENGTH(RECHARGE_INFO), '0')
	, PIN_NUMBER = LPAD('0', LENGTH(PIN_NUMBER), '0')
WHERE CONTRACT_NUM = #{contractNum}
